import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { ChevronDown, SearchLg, XClose, X as CloseX } from '@/icons';
import {
  DialogTrigger,
  Button as AriaButton,
  ListBox as AriaListBox,
} from 'react-aria-components';
import type { Key, Selection } from 'react-aria-components';
import { useFilter } from 'react-aria';
import { Popover } from './BasePopover';
import { SelectItem } from './BaseSelectItem';
import { Badge } from '@/vendor/untitled-ui/base/badges/badges';
import type { SelectItemType } from './baseTypes';
import { cx } from '@/utils/cx';
import { useOverflowCount } from './useOverflowCount';
import { Input } from '@/components/atoms/Input/base/input';
import { WithDataId } from '@/types/withDataId';
import { Button } from '../Button';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export type CreatableMultiSelectItem<T extends Key = Key> = Omit<
  SelectItemType,
  'id'
> & { id: T };

export interface CreatableMultiSelectProps<T extends Key = Key>
  extends WithDataId, Omit<FieldWrapperProps, 'children'> {
  placeholder?: string;
  addOptionPlaceholder?: string;
  addOptionMaxLength?: number;
  searchPlaceholder?: string;
  items?: CreatableMultiSelectItem<T>[];
  /**
   * Fallback options for displaying selected values that may not be in `items`.
   * Useful when:
   * - Selected items are filtered out by search
   * - Options are paginated/lazy-loaded
   * - Async options haven't loaded yet
   *
   * These are NOT shown in the dropdown, only used for badge display.
   */
  preparedOptions?: CreatableMultiSelectItem<T>[];
  selectedKeys?: T[];
  defaultSelectedKeys?: T[];
  isDisabled?: boolean;
  isCreatable?: boolean;
  isRemovable?: boolean;
  isSearchable?: boolean;
  className?: string;
  popoverClassName?: string;
  onChange?: (selectedKeys: T[]) => void;
  onItemAdd?: (label: string) => void;
  onItemRemove?: (key: T, close: () => void) => void;
  onSearch?: (query: string) => void;
  onScrollEnd?: () => void;
  onOpenChange?: (isOpen: boolean) => void;
  t?: {
    addButton: string;
  };
  onBlur?: () => void;
}

const CreatableMultiSelect = <T extends Key = string>({
  placeholder = 'Type to add new options',
  addOptionPlaceholder = 'Add an option',
  addOptionMaxLength = undefined,
  searchPlaceholder = 'Search...',
  items: initialItems = [],
  preparedOptions = [],
  selectedKeys: selectedKeysProp,
  defaultSelectedKeys = [],
  isDisabled = false,
  isCreatable = true,
  isRemovable = false,
  isSearchable = false,
  popoverClassName,
  onChange,
  onItemAdd,
  onItemRemove,
  onSearch,
  onScrollEnd,
  onOpenChange: onOpenChangeProp,
  t = {
    addButton: 'Add',
  },
  'data-id': dataId,
  label,
  hint,
  isInvalid = false,
  isRequired = false,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  onBlur,
}: CreatableMultiSelectProps<T>) => {
  const isControlled = selectedKeysProp !== undefined;

  // Original internal state
  const [items, setItems] =
    useState<CreatableMultiSelectItem<T>[]>(initialItems);
  const [selectedKeys, setSelectedKeys] = useState<Set<T>>(
    new Set(defaultSelectedKeys),
  );
  const [newOptionValue, setNewOptionValue] = useState('');
  const [filterText, setFilterText] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const badgesRef = useRef<HTMLDivElement>(null);
  const hasReachedEnd = useRef(false);

  // Controlled overrides
  const effectiveItems = isControlled ? initialItems : items;
  const effectiveSelectedKeys = useMemo(
    () => (isControlled ? new Set<T>(selectedKeysProp) : selectedKeys),
    [isControlled, selectedKeysProp, selectedKeys],
  );

  // Reset scroll guard when items change (consumer loaded more)
  useEffect(() => {
    if (hasReachedEnd.current) {
      hasReachedEnd.current = false;
    }
  }, [effectiveItems]);

  // Search
  const { contains } = useFilter({ sensitivity: 'base' });
  const filteredItems = useMemo(
    () =>
      // Skip local filtering when onSearch is provided
      onSearch || !filterText
        ? effectiveItems
        : effectiveItems.filter(
            (item) =>
              typeof item.label === 'string' &&
              contains(item.label ?? '', filterText),
          ),
    [effectiveItems, filterText, contains, onSearch],
  );

  // Handler
  const handleSelectionChange = useCallback(
    (keys: Selection) => {
      if (keys === 'all') {
        const allKeys = effectiveItems.map((i) => i.id);
        if (!isControlled) setSelectedKeys(new Set<T>(allKeys));
        onChange?.(allKeys);
        return;
      }
      const next = [...keys] as T[];
      if (!isControlled) setSelectedKeys(new Set<T>(next));
      onChange?.(next);
    },
    [effectiveItems, isControlled, onChange],
  );

  const handleAdd = useCallback(() => {
    const trimmed = newOptionValue.trim();
    if (!trimmed) return;

    const isDuplicate = effectiveItems.some(
      (item) =>
        typeof item.label === 'string' &&
        item.label?.toLowerCase() === trimmed.toLowerCase(),
    );
    if (isDuplicate) {
      setNewOptionValue('');
      return;
    }

    setNewOptionValue('');
    onItemAdd?.(trimmed);

    if (!isControlled) {
      const newItem: CreatableMultiSelectItem<T> = {
        id: trimmed as T,
        label: trimmed,
      };
      setItems((prev) => [...prev, newItem]);
      setSelectedKeys((prev) => {
        const next = new Set(prev);
        next.add(newItem.id);
        onChange?.([...next] as T[]);
        return next;
      });
    }
  }, [newOptionValue, effectiveItems, isControlled, onItemAdd, onChange]);

  const handleRemoveTag = useCallback(
    (key: T) => {
      if (isControlled) {
        const next = new Set(effectiveSelectedKeys);
        next.delete(key);
        onChange?.([...next] as T[]);
      } else {
        setSelectedKeys((prev) => {
          const next = new Set(prev);
          next.delete(key);
          onChange?.([...next] as T[]);
          return next;
        });
      }
    },
    [isControlled, effectiveSelectedKeys, onChange],
  );

  const handleDeleteItem = useCallback(
    (key: T) => {
      if (!isControlled) {
        setItems((prev) => prev.filter((i) => i.id !== key));
        setSelectedKeys((prev) => {
          const next = new Set(prev);
          next.delete(key);
          onChange?.([...next] as T[]);
          return next;
        });
      }
      onItemRemove?.(key, () => setIsOpen(false));
    },
    [isControlled, onChange, onItemRemove],
  );

  const handleRemoveAll = useCallback(() => {
    setSelectedKeys(new Set<T>());
    onChange?.([]);
  }, [onChange]);

  const handleAddInputKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleAdd();
      }
    },
    [handleAdd],
  );

  // Derived display values
  // Look in both effectiveItems and preparedOptions for selected items
  // This ensures badges display correctly even when items are filtered/paginated
  const selectedItems = useMemo(() => {
    const result: CreatableMultiSelectItem<T>[] = [];
    const foundIds = new Set<T>();

    // First, find selected items in effectiveItems
    for (const item of effectiveItems) {
      if (effectiveSelectedKeys.has(item.id)) {
        result.push(item);
        foundIds.add(item.id);
      }
    }

    // Then, look in preparedOptions for any selected items not found
    for (const item of preparedOptions) {
      if (effectiveSelectedKeys.has(item.id) && !foundIds.has(item.id)) {
        result.push(item);
      }
    }

    return result;
  }, [effectiveItems, effectiveSelectedKeys, preparedOptions]);
  const hasSelection = selectedItems.length > 0;
  const hasNewOptionValue = newOptionValue.trim().length > 0;
  const { visibleCount, hiddenCount } = useOverflowCount(
    badgesRef,
    selectedItems.length,
  );

  return (
    <FieldWrapper
      id={id}
      isRequired={isRequired}
      tooltip={tooltip}
      label={label}
      isInvalid={isInvalid}
      labelPosition={labelPosition}
      hint={hint}
      fieldSize={fieldSize}
      description={description}
    >
      <DialogTrigger
        isOpen={isOpen}
        onOpenChange={(open) => {
          setIsOpen(open);
          if (!open) {
            setFilterText('');
            onBlur?.();
          }
          onOpenChangeProp?.(open);
        }}
      >
        <AriaButton
          isDisabled={isDisabled}
          data-id={`${dataId}-trigger`}
          className={({ isFocusVisible }) =>
            cx(
              'relative flex w-full cursor-pointer items-center gap-2 rounded-lg bg-primary shadow-xs ring-1 ring-primary outline-hidden transition duration-100 ease-linear ring-inset py-2 px-3',
              (isFocusVisible || isOpen) && 'ring-2 ring-brand',
              isDisabled &&
                'cursor-not-allowed bg-disabled_subtle text-disabled',
              isInvalid && 'ring-error_subtle',
              !placeholder && 'min-h-9',
            )
          }
        >
          <div className="flex min-w-0 flex-1 items-center gap-1.5">
            {hasSelection ? (
              <>
                <div
                  ref={badgesRef}
                  className="flex flex-1 flex-nowrap items-center gap-1.5 overflow-hidden min-w-0"
                >
                  {selectedItems.map((item, index) => (
                    <Badge
                      key={item.id}
                      type="modern"
                      className={cx(
                        'gap-0.5 shrink-0',
                        index >= visibleCount && 'invisible absolute',
                      )}
                    >
                      {item.label}
                      <span
                        aria-hidden="true"
                        onClick={(e) => {
                          e.stopPropagation();
                          handleRemoveTag(item.id);
                        }}
                        className="flex cursor-pointer items-center justify-center rounded-[3px] p-0.5 transition duration-100 ease-linear hover:bg-utility-gray-100 text-utility-gray-400 hover:text-utility-gray-500"
                      >
                        <CloseX className="size-3 stroke-[3px] transition-inherit-all" />
                      </span>
                    </Badge>
                  ))}
                  {hiddenCount > 0 && (
                    <Badge type="modern">+{hiddenCount}</Badge>
                  )}
                </div>
              </>
            ) : (
              <p
                className={cx(
                  'text-sm text-placeholder',
                  isDisabled && 'text-disabled',
                )}
              >
                {placeholder}
              </p>
            )}
          </div>

          <div className="ml-auto flex shrink-0 items-center gap-1.5">
            {hasSelection && (
              <span
                aria-label="Remove all"
                role="button"
                tabIndex={0}
                onClick={(e) => {
                  e.stopPropagation();
                  handleRemoveAll();
                }}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' || e.key === ' ') {
                    e.stopPropagation();
                    e.preventDefault();
                    handleRemoveAll();
                  }
                }}
                className="flex shrink-0 cursor-pointer items-center justify-center rounded-[3px] p-0.5 transition duration-100 ease-linear hover:bg-utility-gray-100 text-utility-gray-400 hover:text-utility-gray-500"
              >
                <CloseX className="shrink-0 size-4 stroke-[2.5px] transition-inherit-all" />
              </span>
            )}
            <ChevronDown
              aria-hidden="true"
              className="shrink-0 size-4 stroke-[2.5px] text-fg-quaternary"
            />
          </div>
        </AriaButton>

        <Popover
          className={cx('!overflow-hidden flex flex-col', popoverClassName)}
        >
          {isSearchable && (
            <div className={cx('px-3 pt-2', !isCreatable && 'pb-2')}>
              <Input
                value={filterText}
                onChange={(value) => {
                  setFilterText(value);
                  onSearch?.(value);
                }}
                placeholder={searchPlaceholder}
                icon={SearchLg}
                data-id={`${dataId}-search`}
              />
            </div>
          )}

          {isCreatable && (
            <div className="flex items-center gap-2 px-3 py-2">
              <Input
                value={newOptionValue}
                onChange={setNewOptionValue}
                onKeyDown={handleAddInputKeyDown}
                placeholder={addOptionPlaceholder}
                data-id={`${dataId}-input`}
                maxLength={addOptionMaxLength}
              />
              <Button
                onClick={handleAdd}
                isDisabled={!hasNewOptionValue}
                color="secondary"
                data-id={`${dataId}-add-button`}
              >
                {t.addButton}
              </Button>
            </div>
          )}

          <div
            className="overflow-y-auto flex-1 min-h-0"
            onScroll={
              onScrollEnd
                ? (e) => {
                    const target = e.currentTarget;
                    if (
                      !hasReachedEnd.current &&
                      target.scrollHeight -
                        target.scrollTop -
                        target.clientHeight <
                        1
                    ) {
                      hasReachedEnd.current = true;
                      onScrollEnd();
                    }
                  }
                : undefined
            }
          >
            <AriaListBox
              selectionMode="multiple"
              selectedKeys={effectiveSelectedKeys}
              onSelectionChange={handleSelectionChange}
              items={filteredItems}
              className="outline-hidden"
              aria-label={label || 'Options'}
            >
              {(item) => (
                <SelectItem
                  key={String(item.id)}
                  id={item.id}
                  label={item.label}
                  icon={item.icon}
                  avatarUrl={item.avatarUrl}
                  supportingText={item.supportingText}
                  data-id={`${dataId}-${item.id}`}
                  selectedClassName={isRemovable ? 'bg-tertiary' : undefined}
                  action={
                    isRemovable ? (
                      <button
                        type="button"
                        aria-label={`Delete ${item.label}`}
                        onPointerDown={(e) => {
                          e.stopPropagation();
                          e.preventDefault();
                        }}
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDeleteItem(item.id);
                        }}
                        className="ml-auto shrink-0 rounded-sm p-0.5 text-fg-quaternary transition duration-100 ease-linear hover:bg-utility-gray-100 hover:text-fg-secondary"
                      >
                        <XClose className="size-4 stroke-[2px]" />
                      </button>
                    ) : undefined
                  }
                />
              )}
            </AriaListBox>
          </div>
        </Popover>
      </DialogTrigger>
    </FieldWrapper>
  );
};

export { CreatableMultiSelect };
